/**
 * Idempotent stylesheet loader. Injects a <link rel="stylesheet"> into <head>
 * if it hasn't been loaded yet. Returns a Promise that resolves once the sheet
 * is parsed (or immediately on cache hit).
 *
 * @param {string} href — absolute or relative URL of the CSS file
 * @returns {Promise<void>}
 */
const styleCache = new Set();
